from statistics import median, mode
from typing import List, Union, Optional

Numeric = Union[int, float, str, None]


def _to_number(x: Numeric) -> Optional[float]:
    """
    Turn an int, float, numeric string, or None/'N/A' into a float.
    Returns None for values that represent missing data or non-numeric strings.
    """
    # None or explicit missing markers
    if x is None:
        return None
    # Numeric types
    if isinstance(x, (int, float)):
        return float(x)
    # Strings
    if isinstance(x, str):
        s = x.strip()
        # treat common missing indicators as None
        if s.upper() in ("NA", "N/A", "NONE", ""):
            return None
        try:
            return float(s)
        except ValueError:
            # Non-numeric string: treat as missing rather than error
            return None
    # Anything else cannot be converted: treat as missing
    return None


def average_voting(scores: List[Numeric]) -> float:
    nums = [n for n in (_to_number(s) for s in scores) if n is not None]
    return sum(nums) / len(nums) if nums else 0.0


def median_voting(scores: List[Numeric]) -> float:
    nums = [n for n in (_to_number(s) for s in scores) if n is not None]
    return median(nums) if nums else 0.0


def majority_voting(scores: List[Numeric]) -> float:
    nums = [n for n in (_to_number(s) for s in scores) if n is not None]
    try:
        return mode(nums)
    except:
        # fallback to average if no unique mode or no numeric entries
        return average_voting(nums)


def weighted_average_voting(scores: List[Numeric], weights: List[Numeric]) -> float:
    nums = [n for n in (_to_number(s) for s in scores) if n is not None]
    wts  = [n for n in (_to_number(w) for w in weights) if n is not None]
    if len(nums) != len(wts) or not nums:
        return 0.0
    weighted_sum = sum(s * w for s, w in zip(nums, wts))
    total_weight = sum(wts)
    return weighted_sum / total_weight if total_weight else 0.0

AVAILABLE_VOTING_METHODS = {
    "average":          average_voting,
    "median":           median_voting,
    "majority":         majority_voting,
    "weighted_average": weighted_average_voting,
}
